import React, { useState } from 'react';
import { Link, useNavigate } from 'react-router-dom';
import { ToastContainer } from 'react-toastify';
import { handleError, handleSuccess } from '../utils';
import './Signup.css';

function Signup() {
    const [signupInfo, setSignupInfo] = useState({
        name: '',
        email: '',
        password: '',
        role: 'client',
        image: '' // Pour stocker l'image
    });

    const navigate = useNavigate();

    const handleChange = (e) => {
        const { name, value } = e.target;
        setSignupInfo({ ...signupInfo, [name]: value });
    };

    const handleImageChange = (e) => {
        const file = e.target.files[0];
        if (file) {
            const reader = new FileReader();
            reader.onloadend = () => {
                setSignupInfo({ ...signupInfo, image: reader.result });
            };
            reader.readAsDataURL(file);
        }
    };

    const handleSignup = async (e) => {
        e.preventDefault();
        try {
            const response = await fetch('http://localhost:5001/auth/Signup', {
                method: 'POST',
                headers: { 'Content-Type': 'application/json' },
                body: JSON.stringify(signupInfo)
            });
            const result = await response.json();
            if (result.success) {
                handleSuccess(result.message);
                setTimeout(() => navigate('/login'), 1000);
            } else {
                handleError(result.error || result.message);
            }
        } catch (err) {
            handleError(err.message);
        }
    };

    return (
        <div className='signup-container'>
            <div className='signup-form'>
                <h1>Create Account</h1>
                <form onSubmit={handleSignup}>
                    <input type='text' name='name' placeholder='Full Name' onChange={handleChange} value={signupInfo.name} />
                    <input type='email' name='email' placeholder='Email Address' onChange={handleChange} value={signupInfo.email} />
                    <input type='password' name='password' placeholder='Password' onChange={handleChange} value={signupInfo.password} />

                    <label>Profile Picture:</label>
                    <input type='file' accept='image/*' onChange={handleImageChange} />
                    {signupInfo.image && <img src={signupInfo.image} alt='Preview' style={{ width: '100px', height: '100px' }} />}

                    <button type='submit' className='signup-button'>Create Account</button>
                    <p>Already have an account? <Link to='/login'>Login</Link></p>
                </form>
                <ToastContainer />
            </div>
        </div>
    );
}

export default Signup;
